# Category: oauth_security

from flask import Flask, request, jsonify
from flask_oauthlib.provider import OAuth2Provider

app = Flask(__name__)
oauth = OAuth2Provider(app)

auth_codes = {}

@oauth.token_request
def validate_token_request():
    return jsonify({"error": "invalid_client", "error_description": "Invalid client credentials"}), 401

@oauth.authorization_server.register_grant_type("authorization_code")
def generate_authorization_code():
    code = request.form.get("code")
    user_id = request.form.get("user_id")
    auth_codes[code] = user_id
    return jsonify({"code": code}), 200

@oauth.authorization_server.register_grant_type("authorization_code", refresh_token=True)
def exchange_authorization_code_for_token():
    code = request.form.get("code")
    user_id = auth_codes.get(code)
    if user_id is None:
        return jsonify({"error": "invalid_grant", "error_description": "Invalid authorization code"}), 400
    del auth_codes[code]
    return jsonify({"access_token": user_id, "token_type": "bearer"}), 200